"use client";
import React from 'react';

interface HealthMonitorProps {
  symptomsCount: number;
  hasNumbness: boolean;
  breakRatio: number; // 0 to 1
}

export default function HealthMonitor({ symptomsCount, hasNumbness, breakRatio }: HealthMonitorProps) {
  // Logic ประเมินความเสี่ยงระดับ Enterprise
  const getRiskLevel = () => {
    if (symptomsCount >= 5 || hasNumbness) return { label: 'อันตราย', color: '#ef4444', desc: 'ควรพบนักกายภาพบำบัดโดยด่วน' };
    if (symptomsCount >= 3) return { label: 'เฝ้าระวัง', color: '#f59e0b', desc: 'เริ่มมีสัญญาณ Office Syndrome' };
    return { label: 'ปกติ', color: '#10b981', desc: 'รักษาสุขภาพได้ดีมากค่ะท่านโอ๊ค' };
  };

  const risk = getRiskLevel();

  return (
    <div style={cardStyle}>
      <style>{`
        .action-btn:hover { transform: scale(1.05); background: #0369a1 !important; }
      `}</style>
      
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' }}>
        <div>
          <h3 style={titleStyle}>การประเมินสภาวะร่างกาย</h3>
          <p style={descStyle}>{risk.desc}</p>
        </div>
        <div style={{ ...statusBadge, backgroundColor: risk.color }}>{risk.label}</div>
      </div>

      <div style={divider} />

      {/* แนะนำท่าบริหารตามความเสี่ยง */}
      <div style={recommendBox}>
        <span style={hintStyle}>💡 ท่าบริหารแนะนำสำหรับท่านโอ๊ค:</span>
        <h4 style={exerciseTitle}>
          {hasNumbness ? "ท่าบริหารลดอาการชาปลายประสาท" : "ท่ายืดกล้ามเนื้อคอและบ่า (Neck Stretch)"}
        </h4>
        <button className="action-btn" style={actionBtn}>ดูวิธีทำอย่างละเอียด</button>
      </div>

      {/* ระบบแจ้งเตือน (Mockup UI) */}
      <div style={notifStatus}>
        <div style={dot(breakRatio > 0.5 ? '#10b981' : '#f59e0b')} />
        <span>ระบบแจ้งเตือนการพัก: {breakRatio > 0.5 ? 'ทำงานปกติ' : 'ท่านพักน้อยเกินไป'}</span>
      </div>
    </div>
  );
}

const cardStyle = { background: '#fff', padding: '28px', borderRadius: '24px', boxShadow: '0 10px 15px -3px rgba(0,0,0,0.1)', border: '1px solid #e2e8f0', marginBottom: '24px' };
const titleStyle = { fontSize: '20px', fontWeight: '800', color: '#0f172a', margin: 0 };
const descStyle = { color: '#64748b', fontSize: '14px', marginTop: '4px' };
const statusBadge = { color: '#fff', padding: '6px 16px', borderRadius: '12px', fontSize: '14px', fontWeight: '700' };
const divider = { height: '1px', background: '#f1f5f9', margin: '20px 0' };
const recommendBox = { background: '#f8fafc', padding: '16px', borderRadius: '16px', border: '1px dashed #cbd5e1' };
const hintStyle = { fontSize: '12px', color: '#0ea5e9', fontWeight: '700', textTransform: 'uppercase' as const };
const exerciseTitle = { fontSize: '18px', fontWeight: '700', color: '#1e293b', margin: '8px 0' };
const actionBtn = { background: '#0ea5e9', color: '#fff', border: 'none', padding: '8px 16px', borderRadius: '8px', fontWeight: '600', cursor: 'pointer', transition: 'all 0.2s' };
const notifStatus = { display: 'flex', alignItems: 'center', gap: '8px', marginTop: '16px', fontSize: '13px', color: '#64748b' };
const dot = (color: string) => ({ width: '8px', height: '8px', borderRadius: '50%', backgroundColor: color });